+    for size in [1_000, 10_000, 100_000, 1_000_000] {
+        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
+            let mut ewc = EWC::new(1000.0);
+            let params = vec![0.5; size];
