+
+fn majority_bitvectors(vectors: &[Vec<u64>]) -> Vec<u64> {
+    let len = vectors[0].len();
+    (0..len).map(|i| {
+        vectors.iter().map(|v| v[i]).fold(0u64, |acc, x| acc ^ x)
+    }).collect()
