+                    if dist < 10.0 {
+                        max_urgency = max_urgency.max(1.0 - dist / 10.0);
+                    }
+                }
+            }
+        }
+
+        max_urgency.min(1.0)
+    }
+
+    /// Step simulation forward
+    pub fn step(&mut self, real_dt_ms: u64) {
