+            }
+        }
+
+        // Distribute to other agents
+        for (source_id, experiences) in all_transfers {
+            for agent in &mut self.agents {
+                if agent.id != source_id && agent.phase.can_transfer() {
+                    agent.receive_from_peer(experiences.clone());
+                }
