+        // Pop and verify order
+        for i in 0..10 {
+            let event = buffer.pop().unwrap();
+            assert_eq!(event.timestamp(), i as u64);
+        }
+    }
+
+    #[test]
+    fn test_wrap_around() {
+        let buffer = EventRingBuffer::new(4);
