+        let result1 = bind_multiple(&[v1.clone(), v2.clone()]).unwrap();
+        let result2 = v1.bind(&v2);
+
+        assert_eq!(result1, result2);
+    }
+
+    #[test]
+    fn test_bind_multiple_three() {
+        let v1 = Hypervector::random();
+        let v2 = Hypervector::random();
