+        assert_eq!(result1, result2);
+    }
+
+    #[test]
+    fn test_bind_multiple_empty_error() {
+        let result = bind_multiple(&[]);
+        assert!(matches!(result, Err(HdcError::EmptyVectorSet)));
+    }
+}

