+        let values = vec![1.0, 1.0, 1.0];
+        let probs = softmax(&values, 1.0);
+
+        // All probabilities should be equal
+        for &p in &probs {
+            assert_relative_eq!(p, 1.0 / 3.0, epsilon = 1e-6);
+        }
+    }
+
+    #[test]
+    fn test_softmax_sums_to_one() {
